-- SQL дамп данных для импорта в MySQL
-- Использование: импортируйте этот файл в phpMyAdmin после создания схемы

SET FOREIGN_KEY_CHECKS=0;

-- Импорт бонусов
-- Данные из data/bonuses.txt
ON DUPLICATE KEY UPDATE `bonus_balance`=VALUES(`bonus_balance`), `last_updated`=VALUES(`last_updated`), `last_order_id`=VALUES(`last_order_id`);

-- Импорт промокодов (первые несколько из data/promocodes.txt)
ON DUPLICATE KEY UPDATE `name`=VALUES(`name`), `type`=VALUES(`type`), `value`=VALUES(`value`), `ticket_types`=VALUES(`ticket_types`), `start_date`=VALUES(`start_date`), `end_date`=VALUES(`end_date`), `max_uses`=VALUES(`max_uses`), `used_count`=VALUES(`used_count`), `active`=VALUES(`active`), `min_amount`=VALUES(`min_amount`), `notes`=VALUES(`notes`);

-- Импорт пользователей и ролей (из data/roles.txt)
ON DUPLICATE KEY UPDATE `role`=VALUES(`role`), `promo_code`=VALUES(`promo_code`), `updated_at`=VALUES(`updated_at`);

-- Импорт промо-билетов
ON DUPLICATE KEY UPDATE `status`=VALUES(`status`), `used_by`=VALUES(`used_by`), `used_at`=VALUES(`used_at`);

-- Импорт настроек цен
ON DUPLICATE KEY UPDATE `base_price`=VALUES(`base_price`), `discounted_price`=VALUES(`discounted_price`);

SET FOREIGN_KEY_CHECKS=1;

